import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { Role } from '../../core/models';

@Component({
  selector: 'app-tenant-new',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './tenant-new.component.html',
  styleUrl: './tenant-new.component.css',
})
export class TenantNewComponent {
  readonly loading = signal(false);

  readonly form = this.fb.group({
    name: ['', [Validators.required]],
    email: ['', [Validators.required, Validators.email]],
    password: ['', [Validators.required, Validators.minLength(6)]],
    role: ['tenant' as Role, [Validators.required]],
  });

  constructor(
    private fb: FormBuilder,
    private router: Router,
  ) {}

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.loading.set(true);
    const payload = this.form.getRawValue();
    // Mock create — a real app would POST to the API here.
    console.log('Creating tenant', payload);
    setTimeout(() => {
      this.loading.set(false);
      this.router.navigate(['/tenants']);
    }, 500);
  }

  cancel(): void {
    this.router.navigate(['/tenants']);
  }
}
